def build_tags_html(tags):
    return "\n      ".join(f'<span class="paper-tag">{t}</span>' for t in tags)

def build_data_table_rows(rows):
    return "\n        ".join(
        f"<tr><td>{r[0]}</td><td>{r[1]}</td><td>{r[2]}</td><td>{r[3]}</td><td>{r[4]}</td></tr>"
        for r in rows
    )

def build_steps_html(steps):
    return "\n    ".join(
        f'<p class="paper-text"><strong>Step {i+1} — {name}.</strong> {desc}</p>'
        for i, (name, desc) in enumerate(steps)
    )

def build_deliverable2(label, file):
    if not label:
        return ""
    return f'''
      <a href="{file}" class="dl-btn">
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
        {label}
      </a>'''


